module srt_divider(input [3:0] numerator,  
                    input [3:0] obf_denominator,  
                    output reg [3:0] quotient,  
                    output reg remainder);  

    always @(*) begin  
        if (obf_denominator != 0) begin  
            quotient = numerator / obf_denominator;  
            remainder = numerator % obf_denominator;  
        end else begin  
            quotient = 4'b0000;  
            remainder = 1'b0;  
        end  
    end  
endmodule
